import{_ as i,o as e,c as s,a2 as t}from"./chunks/framework.QoSTM79V.js";const c=JSON.parse('{"title":"Mango Infra Test","description":"","frontmatter":{},"headers":[],"relativePath":"mango/mango-infra/mango-infra-test/README.md","filePath":"mango/mango-infra/mango-infra-test/README.md"}'),l={name:"mango/mango-infra/mango-infra-test/README.md"};function n(r,a,o,h,d,p){return e(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="mango-infra-test" tabindex="-1">Mango Infra Test <a class="header-anchor" href="#mango-infra-test" aria-label="Permalink to &quot;Mango Infra Test&quot;">​</a></h1><h2 id="_1-概览" tabindex="-1">1. 概览 <a class="header-anchor" href="#_1-概览" aria-label="Permalink to &quot;1. 概览&quot;">​</a></h2><p><code>mango-infra-test</code> 是 Mango infra 跨模块测试模块，集中验证 KV、Outbox、事件、Realtime、日志配置和多实例场景。它只在 Maven test 阶段使用，不是生产依赖。</p><h2 id="_2-功能清单" tabindex="-1">2. 功能清单 <a class="header-anchor" href="#_2-功能清单" aria-label="Permalink to &quot;2. 功能清单&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>常用入口</th></tr></thead><tbody><tr><td>新增或修改 infra 公共能力后，需要跨模块集成测试</td><td>Maven 依赖 / starter / Java API</td></tr><tr><td>需要验证 Redis、KV sorted set、Outbox、Realtime presence、WebSocket、上行 receiver 等组合行为</td><td>Maven 依赖 / starter / Java API</td></tr><tr><td>需要用 H2 表模拟 infra_kv_entry 或用真实 Redis 验证 Redis store</td><td>Maven 依赖 / starter / Java API</td></tr></tbody></table><h2 id="_3-能力边界" tabindex="-1">3. 能力边界 <a class="header-anchor" href="#_3-能力边界" aria-label="Permalink to &quot;3. 能力边界&quot;">​</a></h2><ul><li>不作为业务模块依赖。</li><li>不放业务功能验收用例。</li><li>不提供生产 migration、Controller 或运行期能力。</li></ul><h2 id="_4-模块入口" tabindex="-1">4. 模块入口 <a class="header-anchor" href="#_4-模块入口" aria-label="Permalink to &quot;4. 模块入口&quot;">​</a></h2><p>测试覆盖范围包括：</p><ul><li>KV store contract、Memory/Redis/JDBC fixture、capability、key namespace、serializer/converter。</li><li>KV Outbox 自动配置、message claim、ack、fail、requeue。</li><li>Domain event outbox 和 Redis Stream transport。</li><li>Realtime 多实例下行、上行、presence、receiver register。</li><li>Log properties 绑定。</li></ul><h2 id="_5-接入方式" tabindex="-1">5. 接入方式 <a class="header-anchor" href="#_5-接入方式" aria-label="Permalink to &quot;5. 接入方式&quot;">​</a></h2><p>业务模块不要依赖本模块。新增 infra 跨模块测试时，在本模块增加测试类或测试 fixture，并通过 Maven test 执行。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango/pom.xml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango-infra/mango-infra-test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span></span></code></pre></div><p>按范围执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango/pom.xml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango-infra/mango-infra-test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Dtest=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;*Kv*&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango/pom.xml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango-infra/mango-infra-test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Dtest=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;*Realtime*&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango/pom.xml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango-infra/mango-infra-test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Dtest=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;*Outbox*&#39;</span></span></code></pre></div><h2 id="_6-配置说明" tabindex="-1">6. 配置说明 <a class="header-anchor" href="#_6-配置说明" aria-label="Permalink to &quot;6. 配置说明&quot;">​</a></h2><p>本模块没有生产配置项。测试资源包括：</p><ul><li><code>src/test/resources/application-realtime-local-test.yml</code></li><li><code>src/test/resources/application-realtime-remote-test.yml</code></li></ul><p>部分真实 Redis 集成测试要求本机 <code>localhost:6379</code> 可用且无密码；测试类注释会标明该要求。</p><h2 id="_7-api-与扩展" tabindex="-1">7. API 与扩展 <a class="header-anchor" href="#_7-api-与扩展" aria-label="Permalink to &quot;7. API 与扩展&quot;">​</a></h2><p>本模块不导出生产 API。可复用测试 fixture 包括：</p><ul><li><code>KvStoreTestFixtures</code>：H2、Redis、Memory store 测试支撑。</li><li>realtime e2e test apps：模拟 local/remote realtime 应用。</li><li>shared presence 和 receiver listener 测试支撑。</li></ul><h2 id="_8-数据与初始化" tabindex="-1">8. 数据与初始化 <a class="header-anchor" href="#_8-数据与初始化" aria-label="Permalink to &quot;8. 数据与初始化&quot;">​</a></h2><p>测试中按需创建 H2 表，例如 <code>infra_kv_entry</code>。这不是生产 migration；生产表结构仍以 <code>mango-infra-kv</code> 的 Flyway migration 为准。</p><h2 id="_9-管理入口" tabindex="-1">9. 管理入口 <a class="header-anchor" href="#_9-管理入口" aria-label="Permalink to &quot;9. 管理入口&quot;">​</a></h2><p>本模块不提供菜单、权限和租户数据。测试会覆盖 tenant id、group、user 等实时投递隔离断言，但这些只服务测试。</p><h2 id="_10-快速开始" tabindex="-1">10. 快速开始 <a class="header-anchor" href="#_10-快速开始" aria-label="Permalink to &quot;10. 快速开始&quot;">​</a></h2><p>新增 infra 能力时：</p><ol><li>在能力模块写单元测试。</li><li>如果能力跨 KV、event、realtime、web、feign 等多个模块，在 <code>mango-infra-test</code> 增加集成测试。</li><li>测试名称表达能力和场景，例如 <code>OutboxAutoConfigurationTest</code>、<code>MangoRealtimeInboundMultiServiceE2ETest</code>。</li><li>在 README 或能力文档的相关文档、排障入口或交付记录中引用对应测试命令。</li></ol><h2 id="_11-问题排查" tabindex="-1">11. 问题排查 <a class="header-anchor" href="#_11-问题排查" aria-label="Permalink to &quot;11. 问题排查&quot;">​</a></h2><ul><li>Redis 测试失败：确认 <code>localhost:6379</code> 可连接，密码为空，或者跳过真实 Redis 范围。</li><li>Realtime e2e 失败：检查端口占用、WebSocket 支持和测试应用上下文启动日志。</li><li>H2 表结构失败：先看 <code>KvStoreTestFixtures</code> 是否和 KV migration 保持一致。</li></ul><h2 id="_12-相关文档" tabindex="-1">12. 相关文档 <a class="header-anchor" href="#_12-相关文档" aria-label="Permalink to &quot;12. 相关文档&quot;">​</a></h2><ul><li><a href="./../../../mango-pmo/rules/backend/05-module">后端模块规范</a></li><li><a href="./../../../mango-pmo/rules/08-capability-docs">能力说明维护规范</a></li><li><a href="./../../../mango-pmo/rules/05-ai-delivery-quality">AI 交付质量门禁</a></li></ul><h2 id="_13-补充资料" tabindex="-1">13. 补充资料 <a class="header-anchor" href="#_13-补充资料" aria-label="Permalink to &quot;13. 补充资料&quot;">​</a></h2><ul><li><a href="./../../../mango-docs/capabilities/README">能力地图</a></li></ul>`,35)])])}const m=i(l,[["render",n]]);export{c as __pageData,m as default};
